/**
* Creates an instance ID generator.
*
* @returns A function that returns a unique sequential ID on each call.
*/
const setupGetInstanceId = () => {
	let instanceId = 0;
	return () => ++instanceId;
};
//#endregion
export { setupGetInstanceId };
